 19→type docxRead struct{}
 20→
 21→func (docxRead) Name() string { return "docx_read" }
 22→
 23→func (docxRead) Description() string {
 24→	return "读取 Word (.docx) 文件文本内容。docx 本质是 ZIP 包，解析其 XML 提取正文段落文本。"
 25→}
 26→
 27→func (docxRead) Schema() json.RawMessage {
 28→	return json.RawMessage(`{
 29→"type":"object",
 30→"properties":{
 31→  "path":{"type":"string","description":"docx文件路径"}
 32→},
 33→"required":["path"]
 34→}`)
 35→}
 36→
 37→func (docxRead) ReadOnly() bool { return true }
 38→
 39→func (docxRead) CompactDescription() string { return compactDesc["docx_read"] }
 40→func (docxRead) CompactSchema() json.RawMessage   { return compactSchema["docx_read"] }
 41→
 42→// docx XML 结构
 43→type docxDocument struct {
 44→	Body docxBody `xml:"body"`
 45→}
 46→type docxBody struct {
 47→	Paragraphs []docxParagraph `xml:"p"`
 48→}
 49→type docxParagraph struct {
 50→	Runs []docxRun `xml:"r"`
 51→}
 52→type docxRun struct {
 53→	Text string `xml:"t"`
 54→}
 55→
 56→func (docxRead) Execute(ctx context.Context, args json.RawMessage) (string, error) {
 57→	var p struct {
 58→		Path string `json:"path"`
 59→	}
 60→	if err := json.Unmarshal(args, &p); err != nil {
 61→		return "", fmt.Errorf("参数无效: %w", err)
 62→	}
 63→	if p.Path == "" {
 64→		return "", fmt.Errorf("path 不能为空")
 65→	}
 66→
 67→	data, err := os.ReadFile(p.Path)
 68→	if err != nil {
 69→		return "", fmt.Errorf("读取文件失败: %w", err)
 70→	}
 71→
 72→	r, err := zip.NewReader(bytes.NewReader(data), int64(len(data)))
 73→	if err != nil {
 74→		return "", fmt.Errorf("不是有效的 docx 文件: %w", err)
 75→	}
 76→
 77→	var docXML []byte
 78→	for _, f := range r.File {
 79→		if f.Name == "word/document.xml" {
 80→			rc, err := f.Open()
 81→			if err != nil {
 82→				return "", fmt.Errorf("打开 document.xml 失败: %w", err)
 83→			}
 84→			docXML, err = io.ReadAll(rc)
 85→			rc.Close()
 86→			if err != nil {
 87→				return "", fmt.Errorf("读取 document.xml 失败: %w", err)
 88→			}
 89→			break
 90→		}
 91→	}
 92→	if docXML == nil {
 93→		return "", fmt.Errorf("未找到 word/document.xml（无效的 docx 文件）")
 94→	}
 95→
 96→	var doc docxDocument
 97→	if err := xml.Unmarshal(docXML, &doc); err != nil {
 98→		return "", fmt.Errorf("解析 document.xml 失败: %w", err)
 99→	}
100→
101→	var lines []string
102→	for _, p := range doc.Body.Paragraphs {
103→		var textParts []string
104→		for _, r := range p.Runs {
105→			textParts = append(textParts, r.Text)
106→		}
107→		line := strings.Join(textParts, "")
108→		if strings.TrimSpace(line) != "" {
109→			lines = append(lines, line)
110→		}
111→	}
112→
113→	return tool.WrapText(strings.Join(lines, "\n")), nil
114→}
