118→type docxWrite struct{}
119→
120→func (docxWrite) Name() string { return "docx_write" }
121→
122→func (docxWrite) Description() string {
123→	return "创建 Word (.docx) 文件：输入文本内容（多行），生成简单的 docx 文件（标题+段落）。"
124→}
125→
126→func (docxWrite) Schema() json.RawMessage {
127→	return json.RawMessage(`{
128→"type":"object",
129→"properties":{
130→  "path":{"type":"string","description":"输出文件路径"},
131→  "title":{"type":"string","description":"文档标题"},
132→  "content":{"type":"string","description":"文档正文（多行文本，空行分割段落）"}
133→},
134→"required":["path","content"]
135→}`)
136→}
137→
138→func (docxWrite) ReadOnly() bool { return false }
139→
140→func (docxWrite) CompactDescription() string { return compactDesc["docx_write"] }
141→func (docxWrite) CompactSchema() json.RawMessage   { return compactSchema["docx_write"] }
142→
143→func (docxWrite) Execute(ctx context.Context, args json.RawMessage) (string, error) {
144→	var p struct {
145→		Path    string `json:"path"`
146→		Title   string `json:"title,omitempty"`
147→		Content string `json:"content"`
148→	}
149→	if err := json.Unmarshal(args, &p); err != nil {
150→		return "", fmt.Errorf("参数无效: %w", err)
151→	}
152→	if p.Path == "" || p.Content == "" {
153→		return "", fmt.Errorf("path 和 content 不能为空")
154→	}
155→
156→	paragraphs := strings.Split(p.Content, "\n\n")
157→	var docXML bytes.Buffer
158→	docXML.WriteString(`<?xml version="1.0" encoding="UTF-8" standalone="yes"?>` + "\n")
159→	docXML.WriteString(`<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">` + "\n")
160→	docXML.WriteString(`<w:body>` + "\n")
161→
162→	if p.Title != "" {
163→		docXML.WriteString(fmt.Sprintf(`<w:p><w:pPr><w:pStyle w:val="Title"/></w:pPr><w:r><w:t>%s</w:t></w:r></w:p>`+"\n", xmlEscape(p.Title)))
164→	}
165→
166→	for _, para := range paragraphs {
167→		para = strings.TrimSpace(para)
168→		if para == "" {
169→			continue
170→		}
171→		docXML.WriteString(`<w:p>`)
172→		// 处理简单Markdown标题
173→		if strings.HasPrefix(para, "## ") {
174→			text := strings.TrimPrefix(para, "## ")
175→			docXML.WriteString(fmt.Sprintf(`<w:pPr><w:pStyle w:val="Heading2"/></w:pPr><w:r><w:t>%s</w:t></w:r>`, xmlEscape(text)))
176→		} else if strings.HasPrefix(para, "# ") {
177→			text := strings.TrimPrefix(para, "# ")
178→			docXML.WriteString(fmt.Sprintf(`<w:pPr><w:pStyle w:val="Heading1"/></w:pPr><w:r><w:t>%s</w:t></w:r>`, xmlEscape(text)))
179→		} else {
180→			docXML.WriteString(fmt.Sprintf(`<w:r><w:t>%s</w:t></w:r>`, xmlEscape(para)))
181→		}
182→		docXML.WriteString(`</w:p>` + "\n")
183→	}
184→
185→	docXML.WriteString(`</w:body>` + "\n")
186→	docXML.WriteString(`</w:document>` + "\n")
187→
188→	// 创建 ZIP
189→	var buf bytes.Buffer
190→	zw := zip.NewWriter(&buf)
191→
192→	writeZipEntry(zw, "[Content_Types].xml", `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
193→<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
194→<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
195→<Default Extension="xml" ContentType="application/xml"/>
196→<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>
197→<Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>
198→</Types>`)
199→
200→	writeZipEntry(zw, "_rels/.rels", `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
201→<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
202→<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>
203→</Relationships>`)
204→
205→	writeZipEntry(zw, "word/document.xml", docXML.String())
206→
207→	writeZipEntry(zw, "word/styles.xml", `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
208→<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
209→<w:style w:type="paragraph" w:styleId="Title"><w:name w:val="Title"/><w:pPr><w:jc w:val="center"/></w:pPr><w:rPr><w:sz w:val="48"/><w:b/></w:rPr></w:style>
210→<w:style w:type="paragraph" w:styleId="Heading1"><w:name w:val="heading 1"/><w:pPr><w:spacing w:before="360"/><w:spacing w:after="120"/></w:pPr><w:rPr><w:sz w:val="32"/><w:b/></w:rPr></w:style>
211→<w:style w:type="paragraph" w:styleId="Heading2"><w:name w:val="heading 2"/><w:pPr><w:spacing w:before="240"/></w:pPr><w:rPr><w:sz w:val="28"/><w:b/></w:rPr></w:style>
212→<w:style w:type="paragraph" w:styleId="Normal"><w:name w:val="Normal"/><w:rPr><w:sz w:val="24"/></w:rPr></w:style>
213→</w:styles>`)
214→
215→	zw.Close()
216→
217→	if err := os.WriteFile(p.Path, buf.Bytes(), 0644); err != nil {
218→		return "", fmt.Errorf("写入文件失败: %w", err)
219→	}
220→
221→	return tool.WrapText(fmt.Sprintf("已创建 docx 文件：%s", p.Path)), nil
222→}
","tool":"read_file"}}

