 15→func init() { tool.RegisterBuiltin(xlsxWrite{}) }
 16→
 17→type xlsxWrite struct{}
 18→
 19→func (xlsxWrite) Name() string { return "xlsx_write" }
 20→
 21→func (xlsxWrite) Description() string {
 22→	return "创建 Excel (.xlsx) 文件：输入表头和数据行，输出 xlsx 文件到指定路径。生成的 xlsx 兼容 Excel 和 WPS。"
 23→}
 24→
 25→func (xlsxWrite) Schema() json.RawMessage {
 26→	return json.RawMessage(`{
 27→"type":"object",
 28→"properties":{
 29→  "path":{"type":"string","description":"输出文件路径（.xlsx）"},
 30→  "sheet_name":{"type":"string","description":"工作表名称","default":"Sheet1"},
 31→  "headers":{"type":"array","items":{"type":"string"},"description":"表头行"},
 32→  "rows":{"type":"array","items":{"type":"array","items":{"type":"string"}},"description":"数据行"}
 33→},
 34→"required":["path","rows"]
 35→}`)
 36→}
 37→
 38→func (xlsxWrite) ReadOnly() bool { return false }
 39→
 40→func (xlsxWrite) CompactDescription() string { return compactDesc["xlsx_write"] }
 41→func (xlsxWrite) CompactSchema() json.RawMessage   { return compactSchema["xlsx_write"] }
 42→
 43→func (xlsxWrite) Execute(ctx context.Context, args json.RawMessage) (string, error) {
 44→	var p struct {
 45→		Path      string     `json:"path"`
 46→		SheetName string     `json:"sheet_name,omitempty"`
 47→		Headers   []string   `json:"headers,omitempty"`
 48→		Rows      [][]string `json:"rows"`
 49→	}
 50→	if err := json.Unmarshal(args, &p); err != nil {
 51→		return "", fmt.Errorf("参数无效: %w", err)
 52→	}
 53→	if p.Path == "" {
 54→		return "", fmt.Errorf("path 不能为空")
 55→	}
 56→	if p.SheetName == "" {
 57→		p.SheetName = "Sheet1"
 58→	}
 59→
 60→	allRows := p.Rows
 61→	if len(p.Headers) > 0 {
 62→		allRows = append([][]string{p.Headers}, allRows...)
 63→	}
 64→
 65→	maxCols := 0
 66→	for _, row := range allRows {
 67→		if len(row) > maxCols {
 68→			maxCols = len(row)
 69→		}
 70→	}
 71→	if maxCols == 0 {
 72→		return "", fmt.Errorf("没有数据")
 73→	}
 74→	// 补全短行
 75→	for i, row := range allRows {
 76→		for len(row) < maxCols {
 77→			row = append(row, "")
 78→		}
 79→		allRows[i] = row
 80→	}
 81→
 82→	// 用col字母生成表头引用
 83→	colLetters := make([]string, maxCols)
 84→	for i := 0; i < maxCols; i++ {
 85→		colLetters[i] = colLetter(i)
 86→	}
 87→
 88→	// 生成 sheet XML
 89→	var sheetXML bytes.Buffer
 90→	sheetXML.WriteString(`<?xml version="1.0" encoding="UTF-8" standalone="yes"?>` + "\n")
 91→	sheetXML.WriteString(`<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">` + "\n")
 92→	sheetXML.WriteString(`<sheetData>` + "\n")
 93→
 94→	for ri, row := range allRows {
 95→		sheetXML.WriteString(fmt.Sprintf(`<row r="%d">`, ri+1))
 96→		for ci, val := range row {
 97→			ref := fmt.Sprintf("%s%d", colLetters[ci], ri+1)
 98→			escaped := xmlEscape(val)
 99→			if val == "" {
100→				sheetXML.WriteString(fmt.Sprintf(`<c r="%s" t="inlineStr"><is><t></t></is></c>`, ref))
101→			} else {
102→				sheetXML.WriteString(fmt.Sprintf(`<c r="%s" t="inlineStr"><is><t>%s</t></is></c>`, ref, escaped))
103→			}
104→		}
105→		sheetXML.WriteString(`</row>` + "\n")
106→	}
107→	sheetXML.WriteString(`</sheetData>` + "\n")
108→	sheetXML.WriteString(`</worksheet>` + "\n")
109→
110→	// 生成 sharedStrings（不使用，改用 inlineStr）
111→	// 生成 styles
112→	stylesXML := `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
113→<styleSheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"/>`
114→
115→	// 生成 workbook
116→	workbookXML := fmt.Sprintf(`<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
117→<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">
118→<sheets><sheet name="%s" sheetId="1" r:id="rId1" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/></sheets>
119→</workbook>`, xmlEscape(p.SheetName))
120→
121→	// 生成 relationships
122→	relsXML := `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
123→<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
124→<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>
125→<Relationship Id="rId2" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>
126→</Relationships>`
127→
128→	// 生成 [Content_Types].xml
129→	contentTypesXML := `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
130→<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
131→<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
132→<Default Extension="xml" ContentType="application/xml"/>
133→<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>
134→<Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>
135→<Override PartName="/xl/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.styles+xml"/>
136→</Types>`
137→
138→	// 创建 ZIP 文件
139→	var buf bytes.Buffer
140→	w := zip.NewWriter(&buf)
141→
142→	writeZipEntry(w, "[Content_Types].xml", contentTypesXML)
143→	writeZipEntry(w, "_rels/.rels", `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
144→<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
145→<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>
146→</Relationships>`)
147→	writeZipEntry(w, "xl/_rels/workbook.xml.rels", relsXML)
148→	writeZipEntry(w, "xl/workbook.xml", workbookXML)
149→	writeZipEntry(w, "xl/styles.xml", stylesXML)
150→	writeZipEntry(w, "xl/worksheets/sheet1.xml", sheetXML.String())
151→
152→	w.Close()
153→
154→	if err := os.WriteFile(p.Path, buf.Bytes(), 0644); err != nil {
155→		return "", fmt.Errorf("写入文件失败: %w", err)
156→	}
157→
158→	return tool.WrapText(fmt.Sprintf("已创建 xlsx 文件：%s（%d 行 %d 列）", p.Path, len(p.Rows), maxCols)), nil
159→}
160→
161→func colLetter(i int) string {
162→	letters := "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
163→	if i < 26 {
164→		return string(letters[i])
165→	}
166→	return colLetter(i/26-1) + string(letters[i%26])
167→}
168→
169→func xmlEscape(s string) string {
170→	s = strings.ReplaceAll(s, "&", "&amp;")
171→	s = strings.ReplaceAll(s, "<", "&lt;")
172→	s = strings.ReplaceAll(s, ">", "&gt;")
173→	s = strings.ReplaceAll(s, "\"", "&quot;")
174→	s = strings.ReplaceAll(s, "'", "&apos;")
175→	return s
176→}
177→
178→func writeZipEntry(w *zip.Writer, name, content string) {
179→	f, _ := w.Create(name)
180→	f.Write([]byte(content))
181→}
","tool":"read_file"}}

{"ok":true,"success":true,"code":"ok","data":{"result":" 1→package skill
 2→
 3→import (
 4→	"fmt"
 5→	"strings"
 6→)
 7→
 8→// IndexMaxChars caps the pinned skills-index block so it can't bloat the
 9→// cache-stable system-prompt prefix; bodies never enter the prefix.
10→const IndexMaxChars = 4000
11→
12→const missingDescPlaceholder = `(no description — frontmatter is missing a "description:" line; tell the user to add one)`
13→
14→// indexHeader introduces the skills block in the system prompt: how to invoke a
15→// skill, and the inline-vs-subagent distinction. V8.22: changed from permissive
16→// "you can invoke" to prescriptive "you MUST consult before acting" to push the
17→// model toward skill usage (Reasonix pattern).
18→const indexHeader = "# Skills — playbooks you MUST consult before acting\n\n" +
19→	"技能是领域知识或工作流编排——使用技能比从零开始更高效、更正确。" +
20→	"在开始任何工作之前，先检查是否有匹配的技能。" +
21→	"各技能的 description 说明了何时必须使用它" +
22→	"（如 \"在任何创造性工作之前必须使用此技能\"）。\n\n" +
23→	"每个条目是内置或用户编写的 playbook。" +
24→	"调用方式: `run_skill({ name: \"<skill-name>\", arguments: \"<task>\" })` " +
25→	"— `name` 只需标识符（如 `\"explore\"`），不要含 `[🧬 subagent]` 标签。" +
26→	"标记 `[🧬 subagent]` 的技能启动隔离子代理——其工具调用和推理不会进入你的上下文，" +
27→	"仅返回最终结论；用于上下文繁重的工作（深度探索、多步研究），你只需结论。" +
28→	"未标记的技能为 inline：正文成为工具结果供你直接阅读执行。" +
29→	"用户也可通过 `/<name>` 调用技能。"
30→
31→// ApplyIndex appends the skills index to basePrompt, or returns it unchanged
32→// when there are no skills. Only names + descriptions (+ a subagent tag) are
33→// listed; bodies load on demand via run_skill.
34→func ApplyIndex(basePrompt string, skills []Skill) string {
35→	if len(skills) == 0 {
36→		return basePrompt
37→	}
38→	lines := make([]string, 0, len(skills))
39→	for _, sk := range skills {
40→		lines = append(lines, indexLine(sk))
41→	}
42→	joined := strings.Join(lines, "\n")
43→	if r := []rune(joined); len(r) > IndexMaxChars {
44→		joined = string(r[:IndexMaxChars]) + fmt.Sprintf("\n… (truncated %d chars)", len(r)-IndexMaxChars)
45→	}
46→	return basePrompt + "\n\n" + indexHeader + "\n\n```\n" + joined + "\n```"
47→}
48→
49→// indexLine renders one skill as "- name [tag] — description", clipped to a
50→// stable width. The subagent tag goes after the name so a model copying the line
51→// into run_skill's `name` arg still yields a clean identifier.
52→func indexLine(sk Skill) string {
53→	desc := strings.TrimSpace(strings.ReplaceAll(sk.Description, "\n", " "))
54→	if desc == "" {
55→		desc = missingDescPlaceholder
56→	}
57→	tag := ""
58→	if sk.RunAs == RunSubagent {
59→		tag = " [🧬 subagent]"
60→	} else if sk.RunAs == RunPipeline {
61→		tag = " [🔗 pipeline]"
62→	}
63→	max := 130 - len([]rune(sk.Name)) - len([]rune(tag))
64→	clipped := clipRunes(desc, max)
65→	if clipped == "" {
66→		return "- " + sk.Name + tag
67→	}
68→	return "- " + sk.Name + tag + " — " + clipped
69→}
70→
71→// clipRunes truncates s to at most max runes (ellipsis included), never
72→// splitting a multi-byte rune.
73→func clipRunes(s string, max int) string {
74→	if max < 1 {
75→		max = 1
76→	}
77→	r := []rune(s)
78→	if len(r) <= max {
79→		return s
80→	}
81→	if max-1 < 1 {
82→		return string(r[:1])
83→	}
84→	return string(r[:max-1]) + "…"
85→}
","tool":"read_file"}}

