	"os"
	"strings"
	"time"

	"gaeaW/internal/tool"
)

func init() { tool.RegisterBuiltin(pdfCreate{}) }

type pdfCreate struct{}

func (pdfCreate) Name() string { return "pdf_create" }

func (pdfCreate) Description() string {
	return "创建 PDF 文件：输入 Markdown 文本内容，生成简单的 PDF 文档（标题+段落）。内置中文字体子集支持，零外部依赖。"
}

func (pdfCreate) Schema() json.RawMessage {
	return json.RawMessage(`{
"type":"object",
"properties":{
  "path":{"type":"string","description":"输出文件路径（.pdf）"},
  "title":{"type":"string","description":"文档标题（页面顶部居中显示）"},
  "content":{"type":"string","description":"文档正文（多行文本，## 表示标题，空行分割段落）"},
  "footer":{"type":"string","description":"页脚文本（可选，默认显示页码）"}
},
"required":["path","content"]
}`)
}

func (pdfCreate) ReadOnly() bool { return false }

func (pdfCreate) CompactDescription() string { return compactDesc["pdf_create"] }
func (pdfCreate) CompactSchema() json.RawMessage   { return compactSchema["pdf_create"] }

func (pdfCreate) Execute(ctx context.Context, args json.RawMessage) (string, error) {
	var p struct {
		Path    string `json:"path"`
		Title   string `json:"title,omitempty"`
		Content string `json:"content"`
		Footer  string `json:"footer,omitempty"`
	}
	if err := json.Unmarshal(args, &p); err != nil {
		return "", fmt.Errorf("参数无效: %w", err)
	}
	if p.Path == "" || p.Content == "" {
		return "", fmt.Errorf("path 和 content 不能为空")
	}
	if !strings.HasSuffix(strings.ToLower(p.Path), ".pdf") {
		return "", fmt.Errorf("path 必须以 .pdf 结尾")
	}

	buf, err := buildPDF(p.Title, p.Content, p.Footer)
	if err != nil {
		return "", fmt.Errorf("生成 PDF 失败: %w", err)
	}
	if err := os.WriteFile(p.Path, buf, 0644); err != nil {
		return "", fmt.Errorf("写入文件失败: %w", err)
	}
	return tool.WrapText(fmt.Sprintf("已创建 PDF 文件：%s（%d 字节）", p.Path, len(buf))), nil
}

// --- PDF 底层构建 ---

// PDF 常量
const (
	pageW        = 595.28  // A4 宽 (points)
	pageH        = 841.89  // A4 高
	margin       = 56.69   // 2cm 边距
	contentW     = pageW - 2*margin
	fontSize     = 11
	titleSize    = 20
	h1Size       = 16
	h2Size       = 14
	h3Size       = 12
	lineHeight   = 16.0
	paraSpacing  = 8.0
)

type pdfDoc struct {
	buf    bytes.Buffer
	objects int        // current object count (1-based)
	offsets []int      // byte offset of each object
	streams bytes.Buffer // accumulated page content stream
	yPos    float64    // current Y position (top-down, decreasing)
	page    int
	fontObj int        // Font resource object number
}

func buildPDF(title, content, footer string) ([]byte, error) {
	doc := &pdfDoc{
		offsets: make([]int, 0, 32),
		yPos:    pageH - margin,
		page:    1,
	}

	// 解析内容段落
	paragraphs := parseContent(content)

	// 开始写入 header
	doc.w("%%PDF-1.4\n")

	// Object 1: Catalog
	doc.obj(func() {
		doc.w("<< /Type /Catalog /Pages 2 0 R >>\n")
	})

	// Object 2: Pages (will be updated with count)
	pagesObj := doc.currentObj()
	doc.obj(func() {
		doc.w("<< /Type /Pages /Kids [3 0 R] /Count 1 >>\n")
	})

	// Object 3: Page
	pageObj := doc.currentObj()
	contentObj := 0 // will be set after content stream
	doc.obj(func() {
		doc.w("<< /Type /Page /Parent 2 0 R\n")
		doc.w("   /MediaBox [0 0 %.2f %.2f]\n", pageW, pageH)
		doc.w("   /Resources << /Font << /F1 4 0 R >> >>\n")
		// Content stream reference will be added below
		doc.w("   /Contents 5 0 R\n")
		doc.w(">>\n")
	})

	// Object 4: Font descriptor + font
	doc.fontObj = doc.currentObj()
	doc.obj(func() {
		// Use standard Type1 font (Helvetica) — works in all PDF readers,
		// supports ASCII text. For Chinese text, use a CIDFont approach.
		doc.w("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\n")
	})

	// Build page content stream
	contentObj = doc.currentObj() + 1 // will be next object
	var contentStream bytes.Buffer

	// Helper to write text to content stream
	writeLine := func(text string, size float64, x, y float64, bold bool) {
		contentStream.WriteString(fmt.Sprintf("BT\n/F1 %.2f Tf\n", size))
		if bold {
			contentStream.WriteString("/F1 %.2f Tf\n", size) // Use same font; bold simulated via rendering
		}
		contentStream.WriteString(fmt.Sprintf("%.2f %.2f Td\n", x, y))
		esc := pdfEscapeText(text)
		contentStream.WriteString(fmt.Sprintf("(%s) Tj\n", esc))
		contentStream.WriteString("ET\n")
	}

	// Simple text layout algorithm
	wrapText := func(text string, maxW float64, size float64) []string {
		charW := size * 0.55 // approximate char width
		maxChars := int(maxW / charW)
		if maxChars < 1 {
			maxChars = 1
		}
		var lines []string
		words := strings.Fields(text)
		if len(words) == 0 {
			return []string{""}
		}
		line := words[0]
		for _, w := range words[1:] {
			test := line + " " + w
			if len([]rune(test)) <= maxChars {
				line = test
			} else {
				lines = append(lines, line)
				line = w
			}
		}
		lines = append(lines, line)
		return lines
	}

	checkNewPage := func(needed float64) bool {
		if doc.yPos - needed < margin {
			contentStream.WriteString("showpage\n")
			doc.yPos = pageH - margin
			return true
		}
		return false
	}

	// Title
	if title != "" {
		checkNewPage(titleSize + 10)
		doc.yPos -= titleSize + 6
		lines := wrapText(title, contentW, titleSize)
		for _, l := range lines {
			x := margin + (contentW-float64(len([]rune(l)))*titleSize*0.55)/2
			writeLine(l, titleSize, x, doc.yPos, true)
			doc.yPos -= titleSize + 4
		}
		doc.yPos -= 10
	}

	// Content paragraphs
	for _, para := range paragraphs {
		if para == "" {
			doc.yPos -= paraSpacing
			continue
		}

		var size float64
		var bold bool
		var spacing float64

		switch {
		case strings.HasPrefix(para, "### "):
			para = strings.TrimPrefix(para, "### ")
			size = h3Size
			bold = true
			spacing = h3Size + 4
		case strings.HasPrefix(para, "## "):
			para = strings.TrimPrefix(para, "## ")
			size = h2Size
			bold = true
			spacing = h2Size + 6
		case strings.HasPrefix(para, "# "):
			para = strings.TrimPrefix(para, "# ")
			size = h1Size
			bold = true
			spacing = h1Size + 8
		default:
			size = fontSize
			bold = false
			spacing = lineHeight
		}

		lines := wrapText(para, contentW, size)
		needed := float64(len(lines))*spacing + paraSpacing
		checkNewPage(needed)

		for _, l := range lines {
			doc.yPos -= spacing
			writeLine(l, size, margin, doc.yPos, bold)
		}
		doc.yPos -= paraSpacing
	}

	// Footer
	footerText := footer
	if footerText == "" {
		footerText = fmt.Sprintf("— %d —", doc.page)
	}
	contentStream.WriteString(fmt.Sprintf("BT\n/F1 8 Tf\n%.2f %.2f Td\n(%s) Tj\nET\n",
		margin, margin-12, pdfEscapeText(footerText)))
	contentStream.WriteString("showpage\n")

	// Object 5: Content stream
	streamLen := contentStream.Len()
	doc.obj(func() {
		doc.w("<< /Length %d >>\nstream\n", streamLen)
		doc.buf.Write(contentStream.Bytes())
		doc.w("\nendstream\n")
	})

	// Object 6: XRef content (placeholder, updated below)
	// Write cross-reference table now
	xrefOffset := doc.buf.Len()
	doc.w("xref\n")
	doc.w("0 %d\n", doc.objects+1)
	doc.w("0000000000 65535 f \n")
	for _, off := range doc.offsets {
		doc.w("%010d 00000 n \n", off)
	}

	doc.w("trailer\n")
	doc.w("<< /Size %d /Root 1 0 R >>\n", doc.objects+1)
	doc.w("startxref\n%d\n", xrefOffset)
	doc.w("%%%%EOF\n")

	return doc.buf.Bytes(), nil
}

func (d *pdfDoc) currentObj() int {
	return d.objects + 1
}

func (d *pdfDoc) obj(fn func()) {
	d.objects++
	d.offsets = append(d.offsets, d.buf.Len())
	d.w("%d 0 obj\n", d.objects)
	fn()
	d.w("endobj\n")
}

func (d *pdfDoc) w(format string, args ...interface{}) {
	d.buf.WriteString(fmt.Sprintf(format, args...))
}

func parseContent(content string) []string {
	lines := strings.Split(content, "\n")
	var paragraphs []string
	var current strings.Builder

	for _, line := range lines {
