{"content": "package builtin

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strings"

	"gaeaW/internal/tool"
)

func init() { tool.RegisterBuiltin(pdfCreate{}) }

type pdfCreate struct{}

func (pdfCreate) Name() string { return "pdf_create" }

func (pdfCreate) Description() string {
	return "创建 PDF 文件：输入 Markdown 文本内容，生成简单的 PDF 文档（标题+段落）。零外部依赖，适合 ASCII 内容。对于中文/非 ASCII 内容，推荐使用 docx_write。"
}

func (pdfCreate) Schema() json.RawMessage {
	return json.RawMessage(`{
"type":"object",
"properties":{
  "path":{"type":"string","description":"输出文件路径（.pdf）"},
  "title":{"type":"string","description":"文档标题（页面顶部居中显示）"},
  "content":{"type":"string","description":"文档正文（多行文本，## 表示标题，空行分割段落）"},
  "footer":{"type":"string","description":"页脚文本（可选，默认留空）"}
},
"required":["path","content"]
}`)
}

func (pdfCreate) ReadOnly() bool { return false }

func (pdfCreate) CompactDescription() string { return compactDesc["pdf_create"] }
func (pdfCreate) CompactSchema() json.RawMessage   { return compactSchema["pdf_create"] }

func (pdfCreate) Execute(ctx context.Context, args json.RawMessage) (string, error) {
	var p struct {
		Path    string `json:"path"`
		Title   string `json:"title,omitempty"`
		Content string `json:"content"`
		Footer  string `json:"footer,omitempty"`
	}
	if err := json.Unmarshal(args, &p); err != nil {
		return "", fmt.Errorf("参数无效: %w", err)
	}
	if p.Path == "" || p.Content == "" {
		return "", fmt.Errorf("path 和 content 不能为空")
	}
	if !strings.HasSuffix(strings.ToLower(p.Path), ".pdf") {
		return "", fmt.Errorf("path 必须以 .pdf 结尾")
	}

	buf := buildPDF(p.Title, p.Content, p.Footer)
	if err := os.WriteFile(p.Path, buf, 0644); err != nil {
		return "", fmt.Errorf("写入文件失败: %w", err)
	}
	return tool.WrapText(fmt.Sprintf("已创建 PDF 文件：%s（%d 字节）", p.Path, len(buf))), nil
}

// --- PDF 底层构建 ---

const (
	a4W       = 595.28
	a4H       = 841.89
	pdfMargin = 56.69  // 2 cm
)

// pdfBuilder 逐步构建 PDF 文件
type pdfBuilder struct {
	buf     bytes.Buffer
	objects int       // 累计对象数
	offsets []int     // 各对象字节偏移
	xrefPos int       // xref 表位置
}

func newPDFBuilder() *pdfBuilder {
	b := &pdfBuilder{offsets: make([]int, 0, 32)}
	b.w("%%PDF-1.4\n")
	return b
}

func (b *pdfBuilder) w(format string, args ...interface{}) {
	b.buf.WriteString(fmt.Sprintf(format, args...))
}

func (b *pdfBuilder) nextObj() int {
	b.objects++
	b.offsets = append(b.offsets, b.buf.Len())
	return b.objects
}

func (b *pdfBuilder) obj(body func()) int {
	num := b.nextObj()
	b.w("%d 0 obj\n", num)
	body()
	b.w("endobj\n")
	return num
}

func (b *pdfBuilder) finish() []byte {
	b.xrefPos = b.buf.Len()
	b.w("xref\n")
	b.w("0 %d\n", b.objects+1)
	b.w("0000000000 65535 f \n")
	for _, off := range b.offsets {
		b.w("%010d 00000 n \n", off)
	}
	b.w("trailer\n")
	b.w("<< /Size %d /Root 1 0 R >>\n", b.objects+1)
	b.w("startxref\n%d\n", b.xrefPos)
	b.w("%%%%EOF\n")
	return b.buf.Bytes()
}

// --- 正文排版 ---

// pdfLayout 管理页面内容流
type pdfLayout struct {
	pageContent bytes.Buffer
	yPos        float64 // 当前 y 坐标（自上而下递减）
	pageNum     int
}

func newPDFLayout() *pdfLayout {
	return &pdfLayout{
		yPos:    a4H - pdfMargin,
		pageNum: 1,
	}
}

func (l *pdfLayout) text(font string, size float64, x, y float64, text string) {
	esc := strings.ReplaceAll(text, "\\", "\\\\")
	esc = strings.ReplaceAll(esc, "(", "\\(")
	esc = strings.ReplaceAll(esc, ")", "\\)")
	l.pageContent.WriteString(fmt.Sprintf("BT\n/%s %.2f Tf\n%.2f %.2f Td\n(%s) Tj\nET\n",
		font, size, x, y, esc))
}

func (l *pdfLayout) newPage() {
	l.pageContent.WriteString("showpage\n")
	l.yPos = a4H - pdfMargin
	l.pageNum++
}

// 估算文本行数（基于字符宽度近似）
func wrapLines(text string, maxWidth float64, fontSize float64) []string {
	charWidth := fontSize * 0.5 // 近似
	maxChars := int(maxWidth / charWidth)
	if maxChars < 1 {
		maxChars = 1
	}
	runes := []rune(text)
	if len(runes) <= maxChars {
		return []string{text}
	}
	var lines []string
	for len(runes) > 0 {
		if len(runes) <= maxChars {
			lines = append(lines, string(runes))
			break
		}
		// 尝试在空格处断行
		cut := maxChars
		for i := maxChars; i > maxChars/2; i-- {
			if runes[i] == ' ' {
				cut = i
				break
			}
		}
		lines = append(lines, string(runes[:cut]))
		runes = runes[cut:]
		// 去除前导空格
		for len(runes) > 0 && runes[0] == ' ' {
			runes = runes[1:]
		}
	}
	return lines
}

func buildPDF(title, content, footer string) []byte {
	b := newPDFBuilder()

	// --- Object 1: Catalog ---
	b.obj(func() {
		b.w("<< /Type /Catalog /Pages 2 0 R >>\n")
	})

	// --- Object 2: Pages ---
	b.obj(func() {
		b.w("<< /Type /Pages /Kids [3 0 R] /Count 1 >>\n")
	})

	// Object 4: Font
	fontObj := b.obj(func() {
		b.w("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\n")
	})

	// 排版内容
	layout := newPDFLayout()
	footerY := pdfMargin + 12

	// 解析段落
	paragraphs := parseParagraphs(content)

	lineH := 15.0
	paraSpace := 8.0

	drawText := func(text string, size float64, bold bool, center bool) {
		lines := wrapLines(text, a4W-2*pdfMargin, size)
		for _, line := range lines {
			if layout.yPos-size < pdfMargin {
				layout.newPage()
			}
			x := pdfMargin
			if center {
				lineW := float64(len([]rune(line))) * size * 0.5
				x = (a4W - lineW) / 2
			}
			layout.yPos -= size + 2
			layout.text("F1", size, x, layout.yPos, line)
		}
	}

	// 标题
	if title != "" {
		drawText(title, 22, true, true)
		layout.yPos -= 12
	}

	// 正文
	for _, para := range paragraphs {
		if para == "" {
			layout.yPos -= paraSpace / 2
			continue
		}

		var size float64
		var bold bool
		var spaceAfter float64

		switch {
		case strings.HasPrefix(para, "### "):
			para = strings.TrimPrefix(para, "### ")
			size, bold, spaceAfter = 12, true, 4
		case strings.HasPrefix(para, "## "):
			para = strings.TrimPrefix(para, "## ")
			size, bold, spaceAfter = 14, true, 6
		case strings.HasPrefix(para, "# "):
			para = strings.TrimPrefix(para, "# ")
			size, bold, spaceAfter = 16, true, 8
		default:
			size, bold, spaceAfter = 11, false, lineH
		}

		lines := wrapLines(para, a4W-2*pdfMargin, size)
		for _, line := range lines {
			if layout.yPos-size < pdfMargin {
				layout.newPage()
			}
			layout.yPos -= spaceAfter
			layout.text("F1", size, pdfMargin, layout.yPos, line)
			spaceAfter = lineH // 后续行用行高
		}
		layout.yPos -= paraSpace
	}

	// 页脚
	if footer != "" {
		layout.text("F1", 8, pdfMargin, footerY, footer)
	} else {
		layout.text("F1", 8, pdfMargin, footerY, fmt.Sprintf("— %d —", layout.pageNum))
	}

	pageContentData := layout.pageContent.Bytes()

	// --- Object 5: Content Stream ---
	b.obj(func() {
		b.w("<< /Length %d >>\nstream\n", len(pageContentData))
		b.buf.Write(pageContentData)
		b.w("\nendstream\n")
	})

	// --- 回到 Object 3: 页面（需要知道 Font 和 Contents 的 obj 号）---
	// 用前瞻方式，最后的 obj 号是确定的
	// 我们实际 obj 顺序: 1-Catalog, 2-Pages, 3-Page, 4-Font, 5-Contents
	_ = fontObj // F1 = Font object 4
	b.obj(func() {
		b.w("<< /Type /Page /Parent 2 0 R\n")
		b.w("   /MediaBox [0 0 %.2f %.2f]\n", a4W, a4H)
		b.w("   /Resources << /Font << /F1 4 0 R >> >>\n")
		b.w("   /Contents 5 0 R\n")
		b.w(">>\n")
	})

	return b.finish()
}

func parseParagraphs(content string) []string {
	lines := strings.Split(content, "\n")
	var paras []string
	var cur strings.Builder

	for _, line := range lines {
		trim := strings.TrimSpace(line)
		if trim == "" {
			if cur.Len() > 0 {
				paras = append(paras, cur.String())
				cur.Reset()
			}
			continue
		}
		if cur.Len() > 0 {
			// 如果当前行以 # 开头（标题），前一段结束
			if strings.HasPrefix(trim, "#") && strings.HasPrefix(trim, "#") {
				paras = append(paras, cur.String())
				cur.Reset()
			} else {
				cur.WriteString(" ")
			}
		}
		cur.WriteString(trim)
	}
	if cur.Len() > 0 {
		paras = append(paras, cur.String())
	}
	return paras
}
