// splitLines 根据字体大小近似换行
func splitLines(text string, maxW, fontSize float64) []string {
	cw := fontSize * 0.5
	max := int(maxW / cw)
	if max < 1 {
		max = 1
	}
	runes := []rune(text)
	if len(runes) <= max {
		return []string{text}
	}
	var out []string
	for len(runes) > 0 {
		if len(runes) <= max {
			out = append(out, string(runes))
			break
		}
